SELECT COUNT(*) AS total_changes
FROM historical_changes
WHERE retiree_id = 2;

SELECT SUM(pension_amount) AS total_pension_amount
FROM pensions
WHERE retiree_id IN (SELECT retiree_id FROM benefits WHERE benefit_type = 'dental');

SELECT COUNT(*) 
FROM historical_changes 
WHERE retiree_id = 1 AND change_type = 'pension';

SELECT total_amount, compensation_year
FROM total_compensation
ORDER BY compensation_year DESC;

SELECT pension_amount
FROM pensions
WHERE retiree_id = 2 AND pension_year = '2021';

SELECT SUM(total_amount) AS total_compensation
FROM total_compensation
WHERE compensation_year = '2021';

SELECT pension_id
FROM pensions
WHERE retiree_id = 2;

SELECT pension_year
FROM pensions
WHERE retiree_id = 1 AND pension_amount > (SELECT AVG(pension_amount) FROM pensions WHERE retiree_id = 1);

SELECT DISTINCT pension_year 
FROM pensions 
WHERE retiree_id = 1;

SELECT SUM(pension_amount) AS total_pension_payout
FROM pensions
WHERE pension_year = '2021' AND payment_frequency = 'monthly';
